targets.expr:
(
  sum by (hostname, type) (
    rate(scm_block_location_protocol_time{instance=~"$scm"}[$__rate_interval])
  )
  /
  sum by (hostname, type) (
    clamp_min(
      rate(scm_block_location_protocol_counter{instance=~"$scm"}[$__rate_interval]),
      1e-12
    )
  )
)

sum by (hostname) (
  rate(scm_block_deleting_service_num_block_deletion_command_sent[$__rate_interval])
  and on (hostname)
  sum by (hostname) (
    clamp_max(
      jvm_metrics_mem_heap_used_m{
        instance=~"$scm",
        processname="StorageContainerManager"
      },
      1
    )
  )
)

sum by (hostname) (
  rate(scm_block_deleting_service_num_block_deletion_command_success[$__rate_interval])
  and on (hostname)
  sum by (hostname) (
    clamp_max(
      jvm_metrics_mem_heap_used_m{
        instance=~"$scm",
        processname="StorageContainerManager"
      },
      1
    )
  )
)

sum by (hostname) (
  rate(scm_block_deleting_service_num_block_deletion_command_failure[$__rate_interval])
  and on (hostname)
  sum by (hostname) (
    clamp_max(
      jvm_metrics_mem_heap_used_m{
        instance=~"$scm",
        processname="StorageContainerManager"
      },
      1
    )
  )
)

sum by (hostname) (
  rate(scm_block_deleting_service_num_block_deletion_transaction_completed[$__rate_interval])
  and on (hostname)
  sum by (hostname) (
    clamp_max(
      jvm_metrics_mem_heap_used_m{
        instance=~"$scm",
        processname="StorageContainerManager"
      },
      1
    )
  )
)
